 22→
 23→  const handleSubmit = async (e) => {
 24→    e.preventDefault();
 25→    setLoading(true);
 26→    setFormError(validateForm(formValue));
 27→
 28→    if (Object.keys(validateForm(formValue)).length > 0) {
 29→      setLoading(false);
 30→      return null;
 31→    } else {
 32→      let captchaToken = captchaRef.current?.getValue();
 33→      if (captchaToken.length === 0) {
 34→        setCaptchaError("ReCaptcha is mandatory");
 35→        setLoading(false);
 36→        return;
 37→      }
 38→      window.scrollTo(0, 0);
 39→      const verify = await verifyCaptcha(captchaToken);
 40→      captchaRef.current?.reset();
 41→      if (verify) {
 42→        setSubmit(true);
 43→        setFormValue({
 44→          firstname: "",
 45→          lastname: "",
 46→          email: "",
 47→          message: "",
 48→        });
 49→        setCaptchaError("");
 50→        setLoading(false);
 51→      } else {
 52→        setSubmit(false);
 53→        setFormValue({
 54→          firstname: "",
 55→          lastname: "",
 56→          email: "",
 57→          message: "",
 58→        });
 59→        setCaptchaError("");
 60→        setLoading(false);
 61→      }
 62→    }
